function getvartext (str, vars)
	local escape = function (s)
		s = tostring (s)
		local ret = s:gsub ('\\', '\\\\'):gsub ('"', '\\"')
		return ret
	end

	local ret = {
		'#!"',
		escape (str),
		'"',
	}
	if (type (vars) == 'table') then
		for var, value in pairs (vars) do
			table.insert (ret, ';')
			table.insert (ret, var)
			table.insert (ret, '="')
			table.insert (ret, escape (value))
			table.insert (ret, '"')
		end
	end
	return table.concat (ret)
end

